  ('dietitian-moex-09235', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', 'Fattyacyl-CoA如要從細胞質通過粒腺體膜進入粒腺體內需要何種carrier的幫忙？', '["黃素 腺嘌 呤 核 苷雙磷 酸（FAD）", "肉鹼（carnitine）", "細胞色素（cytochrome）", "輔 酶A（coenzymeA）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "9eccf64019e8", "answer_pdf_sha1": "a86ad875c042", "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09236', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', 'ApoproteinB100主要發現於下列何種Lipoprotein？', '["高密度脂蛋白（HDL）", "低密度脂蛋白（LDL）", "極低密度脂蛋白（VLDL）", "乳靡微粒（chylomicrons）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "9eccf64019e8", "answer_pdf_sha1": "a86ad875c042", "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09237', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '以下何種胺基酸容易破壞螺蛋白質的α-螺旋（α-helix）結構？', '["甲硫胺酸（methionine）", "丙胺酸（alanine）", "甘胺酸（glycine）", "白胺酸（leucine）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "9eccf64019e8", "answer_pdf_sha1": "a86ad875c042", "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09238', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '醣解（Glycolysis）過程中第一個ATP投資反應為何？', '["α-D-Glucose→α-D-glucose-6-phosphate", "α-D-Glucose-6-phosphate→D-Fructose-6-phosphate", "D-Fructose-6-phosphate→D-Fructose-1,6-bisphosphate", "以上皆非"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "9eccf64019e8", "answer_pdf_sha1": "a86ad875c042", "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09239', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '以下那一個關於胺基酸的敘述錯誤？', '["結胺酸（Valine）和丙胺酸（Alanine）是中性，非極性胺基酸", "離胺酸（Lysine）和精胺酸（Arginine）是鹼性胺基酸", "色胺酸（Tryptophan）和苯丙胺酸（Phenylalanine）是芳香族胺基酸", "天門冬胺酸（Asparticacid）和天門冬醯胺酸（Asparagine）是酸性胺基酸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "9eccf64019e8", "answer_pdf_sha1": "a86ad875c042", "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
